const meeting = $json;

const directory = {
  "Brandon Stewart": "brandon@blazeproperty.com",
  "Amy": "amy@blazeproperty.com",
  "Breanna": "breanna@blazeproperty.com",
  "Debbie": "debbie@blazeproperty.com",
  "Dede": "dede@blazeproperty.com",
  "Shelbie": "shelbie@blazeproperty.com",
  "Chris": "chris@blazeproperty.com",
  "Ashlie": "ashlie@blazeproperty.com"
};

const required = ["brandon@blazeproperty.com"];

const participants = meeting.participants || [];

const resolved = [];

for (const p of participants) {
  if (!p) continue;
  const v = String(p).trim();

  if (v.includes('@')) {
    resolved.push(v.toLowerCase());
    continue;
  }

  if (directory[v]) {
    resolved.push(directory[v]);
  }
}

const fallback = directory[meeting.manager_name];
if (fallback) resolved.push(fallback);

const recipients = [...new Set([...required, ...resolved])];

return [{ json: { ...meeting, recipients } }];

const m = $json;

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function shorten(text, max = 260) {
  const t = String(text || '').replace(/\s+/g, ' ').trim();
  if (t.length <= max) return t;
  return t.substring(0, max).trim() + '...';
}

function splitUsefulLines(text) {
  return String(text || '')
    .split(/\n+/)
    .map(s => s.trim())
    .filter(Boolean)
    .filter(s => !/^rate this summary/i.test(s))
    .filter(s => !/^helpful or not helpful/i.test(s));
}

function formatShortList(arr, maxItems = 3, maxChars = 280) {
  if (!Array.isArray(arr) || arr.length === 0) {
    return '<p style="color:#666;margin:0;">None</p>';
  }

  const lines = arr
    .flatMap(splitUsefulLines)
    .filter(Boolean)
    .slice(0, maxItems);

  if (!lines.length) {
    return '<p style="color:#666;margin:0;">None</p>';
  }

  return lines.map(i => `
    <div style="margin-bottom:8px;padding:10px 12px;background:#f9fafb;border-left:4px solid #374151;border-radius:6px;">
      ${escapeHtml(shorten(i, maxChars))}
    </div>
  `).join('');
}

function formatDecisions(arr) {
  if (!Array.isArray(arr) || arr.length === 0) {
    return '<p style="color:#666;margin:0;">None</p>';
  }

  const lines = arr.flatMap(splitUsefulLines).filter(Boolean);

  return lines.map(i => `
    <div style="margin-bottom:8px;padding:10px 12px;background:#eef6ff;border-left:4px solid #1d4ed8;border-radius:6px;">
      ${escapeHtml(shorten(i, 320))}
    </div>
  `).join('');
}

function formatActions(actions) {
  if (!Array.isArray(actions) || actions.length === 0) {
    return '<p style="margin:0;color:#666;">No action items found.</p>';
  }

  return actions.map((a, index) => `
    <tr>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;vertical-align:top;width:34px;color:#6b7280;">
        ${index + 1}
      </td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;vertical-align:top;">
        <strong>${escapeHtml(a.action_description)}</strong>
        ${a.property_name ? `<div style="margin-top:4px;color:#6b7280;font-size:13px;">Property: ${escapeHtml(a.property_name)}</div>` : ''}
      </td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;vertical-align:top;white-space:nowrap;">
        ${escapeHtml(a.action_owner)}
      </td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;vertical-align:top;white-space:nowrap;">
        ${escapeHtml(a.due_date)}
      </td>
    </tr>
  `).join('');
}

const dt = new Date(String(m.meeting_datetime).replace(' ', 'T'));
const meetingDate = dt.toLocaleDateString('en-US', {
  weekday: 'short',
  month: 'short',
  day: 'numeric',
  year: 'numeric'
});

const actionCount = Array.isArray(m.actions) ? m.actions.length : Number(m.action_count || 0);

const summaryHtml = formatShortList(m.summary_structured?.changes, 3, 280);
const issuesHtml = formatShortList(m.summary_structured?.issues, 3, 300);
const decisionsHtml = formatDecisions(m.summary_structured?.decisions);

const subject = `Meeting Follow-Up – ${m.manager_name} – ${meetingDate}`;

const body = `
<div style="font-family:Arial,sans-serif;background:#f3f4f6;padding:20px;color:#111827;">
  <div style="max-width:760px;margin:0 auto;background:#ffffff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden;">

    <div style="background:#111827;color:#ffffff;padding:20px 24px;">
      <div style="font-size:12px;text-transform:uppercase;letter-spacing:.08em;color:#d1d5db;">
        WMMA Meeting Follow-Up
      </div>
      <div style="font-size:24px;font-weight:700;margin-top:6px;">
        ${escapeHtml(m.manager_name)}
      </div>
      <div style="font-size:14px;color:#d1d5db;margin-top:6px;">
        ${escapeHtml(meetingDate)} · Week of ${escapeHtml(m.week_reference)} · ${escapeHtml(actionCount)} action item${actionCount === 1 ? '' : 's'}
      </div>
    </div>

    <div style="padding:22px 24px;">

      <div style="margin-bottom:22px;">
        <h2 style="font-size:17px;margin:0 0 10px;border-bottom:2px solid #e5e7eb;padding-bottom:8px;">
          Quick Summary
        </h2>
        ${summaryHtml}
      </div>

      <div style="margin-bottom:22px;">
        <h2 style="font-size:17px;margin:0 0 10px;border-bottom:2px solid #e5e7eb;padding-bottom:8px;">
          Key Issues
        </h2>
        ${issuesHtml}
      </div>

      <div style="margin-bottom:22px;">
        <h2 style="font-size:17px;margin:0 0 10px;border-bottom:2px solid #e5e7eb;padding-bottom:8px;">
          Decisions
        </h2>
        ${decisionsHtml}
      </div>

      <div style="margin-bottom:22px;">
        <h2 style="font-size:17px;margin:0 0 10px;border-bottom:2px solid #e5e7eb;padding-bottom:8px;">
          Action Items
        </h2>

        <table style="width:100%;border-collapse:collapse;border:1px solid #e5e7eb;border-radius:8px;overflow:hidden;font-size:14px;">
          <thead>
            <tr style="background:#f9fafb;">
              <th style="text-align:left;padding:10px;border-bottom:1px solid #e5e7eb;width:34px;">#</th>
              <th style="text-align:left;padding:10px;border-bottom:1px solid #e5e7eb;">Action</th>
              <th style="text-align:left;padding:10px;border-bottom:1px solid #e5e7eb;">Owner</th>
              <th style="text-align:left;padding:10px;border-bottom:1px solid #e5e7eb;">Due</th>
            </tr>
          </thead>
          <tbody>
            ${formatActions(m.actions)}
          </tbody>
        </table>
      </div>

      <div style="margin-top:22px;padding:13px 14px;background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;font-size:14px;">
        Please review your assigned items and begin execution immediately.
      </div>

      <p style="margin-top:20px;">- Brandon</p>

      <p style="margin-top:16px;font-size:12px;color:#6b7280;">
        Full meeting detail is retained in the meeting record.
      </p>
    </div>
  </div>
</div>
`;

return [{ json: { ...m, subject, body } }];

